// Framework-neutral validation wiring (works in Angular/React the same way).
function validateEmail(input: HTMLInputElement): boolean {
  const error = document.getElementById('email-error')!;
  const valid = /.+@.+\..+/.test(input.value);

  input.setAttribute('aria-invalid', String(!valid));

  if (!valid) {
    // Setting text in a role="alert" region announces it to screen readers.
    error.textContent = 'Enter a valid email address, e.g. name@example.com.';
    // On submit, move focus to the FIRST invalid field so the
    // keyboard/SR user is taken straight to the problem.
    input.focus();
  } else {
    error.textContent = '';
  }
  return valid;
}

const dialog = document.getElementById('dialog')!;
const openBtn = document.getElementById('open-btn')!;
const closeBtn = document.getElementById('close-btn')!;
let lastFocused: HTMLElement | null = null;

const FOCUSABLE =
  'a[href], button:not([disabled]), input:not([disabled]),' +
  ' select, textarea, [tabindex]:not([tabindex="-1"])';

function openDialog() {
  lastFocused = document.activeElement as HTMLElement; // remember trigger
  dialog.hidden = false;
  const focusables = dialog.querySelectorAll<HTMLElement>(FOCUSABLE);
  focusables[0]?.focus();                              // move focus IN
  document.addEventListener('keydown', onKeydown);
}

function closeDialog() {
  dialog.hidden = true;
  document.removeEventListener('keydown', onKeydown);
  lastFocused?.focus();                                // restore focus
}

function onKeydown(e: KeyboardEvent) {
  if (e.key === 'Escape') { closeDialog(); return; }
  if (e.key !== 'Tab') return;

  // Focus trap: cycle Tab / Shift+Tab within the dialog only.
  const items = Array.from(dialog.querySelectorAll<HTMLElement>(FOCUSABLE));
  if (items.length === 0) return;
  const first = items[0];
  const last = items[items.length - 1];

  if (e.shiftKey && document.activeElement === first) {
    e.preventDefault();
    last.focus();
  } else if (!e.shiftKey && document.activeElement === last) {
    e.preventDefault();
    first.focus();
  }
}

openBtn.addEventListener('click', openDialog);
closeBtn.addEventListener('click', closeDialog);

// Angular: focus main + announce on every NavigationEnd.
import { LiveAnnouncer } from '@angular/cdk/a11y';

constructor(router: Router, announcer: LiveAnnouncer, title: Title) {
  router.events
    .pipe(filter(e => e instanceof NavigationEnd))
    .subscribe(() => {
      const pageTitle = title.getTitle();
      const main = document.getElementById('main');
      main?.focus();                       // main has tabindex="-1"
      announcer.announce(pageTitle, 'polite'); // speak the new view
    });
}

