class AccessibleModal {
  private dialog: HTMLElement;
  private trigger: HTMLElement | null = null;
  private readonly FOCUSABLE =
    'a[href], button:not([disabled]), input:not([disabled]),' +
    ' select:not([disabled]), textarea:not([disabled]),' +
    ' [tabindex]:not([tabindex="-1"])';

  constructor(dialogEl: HTMLElement) {
    this.dialog = dialogEl;
    // role/name via markup: role="dialog" aria-modal="true"
    //   aria-labelledby="dialog-title"
    this.onKeydown = this.onKeydown.bind(this);
  }

  private focusable(): HTMLElement[] {
    return Array.from(this.dialog.querySelectorAll<HTMLElement>(this.FOCUSABLE));
  }

  open(): void {
    this.trigger = document.activeElement as HTMLElement; // remember opener
    this.dialog.hidden = false;
    this.dialog.setAttribute('aria-modal', 'true');
    const items = this.focusable();
    (items[0] ?? this.dialog).focus();                     // focus IN
    document.addEventListener('keydown', this.onKeydown);
  }

  close(): void {
    this.dialog.hidden = true;
    document.removeEventListener('keydown', this.onKeydown);
    this.trigger?.focus();                                 // restore focus
  }

  private onKeydown(e: KeyboardEvent): void {
    if (e.key === 'Escape') {
      e.preventDefault();
      this.close();
      return;
    }
    if (e.key !== 'Tab') return;

    const items = this.focusable();
    if (items.length === 0) {
      e.preventDefault();          // nothing to move to; keep focus contained
      return;
    }
    const first = items[0];
    const last = items[items.length - 1];
    const active = document.activeElement;

    if (e.shiftKey && active === first) {
      e.preventDefault();
      last.focus();                // wrap backward
    } else if (!e.shiftKey && active === last) {
      e.preventDefault();
      first.focus();               // wrap forward
    }
  }
}

